// src/utils/firebase.js
import { initializeApp } from "firebase/app";
import {
  getFirestore,
  collection,
  addDoc,
  getDocs,
  query,
  orderBy,
  limit,
  where,
} from "firebase/firestore";
import {
  getAuth,
  createUserWithEmailAndPassword,
  signInWithEmailAndPassword,
  signOut,
  onAuthStateChanged,
  updateProfile,
} from "firebase/auth";

const firebaseConfig = {
  apiKey: "AIzaSyBihVc93BZ5mubGZQVhmzsz-wkeVXkpreI",
  authDomain: "clario-28105.firebaseapp.com",
  projectId: "clario-28105",
  storageBucket: "clario-28105.firebasestorage.app",
  messagingSenderId: "495711462842",
  appId: "1:495711462842:web:201da00b5a38490e252983",
  measurementId: "G-CVGF9WL7JW",
};

const app = initializeApp(firebaseConfig);

export const db = getFirestore(app);
export const auth = getAuth(app);


// ─────────────────────────────
// AUTH FUNCTIONS
// ─────────────────────────────

export async function registerUser(name, email, password) {
  const cred = await createUserWithEmailAndPassword(auth, email, password);
  await updateProfile(cred.user, { displayName: name });
  return cred.user;
}

export async function loginUser(email, password) {
  const cred = await signInWithEmailAndPassword(auth, email, password);
  return cred.user;
}

export async function logoutUser() {
  await signOut(auth);
}

export function onAuthChange(callback) {
  return onAuthStateChanged(auth, callback);
}


// ─────────────────────────────
// SESSION FUNCTIONS (PER USER)
// ─────────────────────────────

export async function saveSession(sessionData) {
  try {
    const user = auth.currentUser;

    // ❗ IMPORTANT: only save if user is logged in
    if (!user) {
      console.error("❌ Cannot save session: No logged-in user");
      return;
    }

    console.log("💾 Saving session for:", user.uid);

    const docRef = await addDoc(collection(db, "sessions"), {
      ...sessionData,

      // 🔥 THIS LINKS DATA TO THE ACCOUNT
      userId: user.uid,
      userEmail: user.email,

      createdAt: new Date(),
    });

    console.log("✅ Session saved:", docRef.id);
  } catch (e) {
    console.error("❌ Firebase save failed:", e);
  }
}


export async function getSessions(limitCount = 20) {
  try {
    const user = auth.currentUser;

    // ❗ IMPORTANT: only fetch if logged in
    if (!user) {
      console.error("❌ Cannot fetch sessions: No logged-in user");
      return [];
    }

    console.log("📥 Fetching sessions for:", user.uid);

    const q = query(
      collection(db, "sessions"),

      // 🔥 ONLY GET THIS USER’S DATA
      where("userId", "==", user.uid),

      orderBy("createdAt", "desc"),
      limit(limitCount)
    );

    const snap = await getDocs(q);

    const sessions = snap.docs.map((d) => ({
      id: d.id,
      ...d.data(),
    }));

    console.log("✅ Sessions fetched:", sessions);

    return sessions;
  } catch (e) {
    console.error("❌ Firebase fetch failed:", e);
    return [];
  }
}
